-- Create "payment_profiles" table
CREATE TABLE "payment_profiles" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "deleted_at" timestamptz NULL, "user_id" bigint NOT NULL, "pan_masked" character varying NOT NULL, "holder" character varying NOT NULL, "email" character varying NOT NULL, "phone" character varying NOT NULL, "user_token" character varying NOT NULL, "recurrent_token" character varying NULL, PRIMARY KEY ("id"));
-- Create index "payment_profiles_recurrent_token_key" to table: "payment_profiles"
CREATE UNIQUE INDEX "payment_profiles_recurrent_token_key" ON "payment_profiles" ("recurrent_token");
-- Modify "invoices" table
ALTER TABLE "invoices" ADD COLUMN "payment_provider" character varying NOT NULL DEFAULT 'APP_STORE', ADD COLUMN "payment_profile_id" bigint NULL, ADD CONSTRAINT "invoices_payment_profiles_invoices" FOREIGN KEY ("payment_profile_id") REFERENCES "payment_profiles" ("id") ON UPDATE NO ACTION ON DELETE SET NULL;
-- Rename a column from "apple_store_transaction_id" to "external_transaction_id"
ALTER TABLE "invoices" RENAME COLUMN "apple_store_transaction_id" TO "external_transaction_id";
-- Modify "products" table
ALTER TABLE "products" ADD COLUMN "payment_model" character varying NOT NULL DEFAULT 'RECURRENT';
-- Create "product_reservations" table
CREATE TABLE "product_reservations" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "product_id" bigint NOT NULL, "invoice_id" bigint NOT NULL, "user_id" bigint NOT NULL, "reserved_quantity" bigint NOT NULL DEFAULT 1, "status" character varying NOT NULL DEFAULT 'PENDING', "expiration_time" timestamptz NOT NULL, "invoice_reservations" bigint NOT NULL, "product_reservations" bigint NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "product_reservations_invoices_reservations" FOREIGN KEY ("invoice_reservations") REFERENCES "invoices" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "product_reservations_products_reservations" FOREIGN KEY ("product_reservations") REFERENCES "products" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
